function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const graph: Map<number, Map<number, number>> = new Map();

    // Build the graph
    for (const [u, v, cost] of edges) {
        if (!graph.has(u)) {
            graph.set(u, new Map());
        }
        graph.get(u)!.set(v, cost);
    }

    // Use a priority queue for Dijkstra's algorithm, sorted by minimum edge cost
    const pq: [number, number, number][] = [];
    pq.push([0, 0, Infinity]); // [minEdgeCost, currentNode, totalCost]
    const visited: Set<number> = new Set();
    const maxMinEdgeCost: number[] = new Array(n).fill(-1);

    while (pq.length > 0) {
        // Sort by minEdgeCost (priority queue)
        pq.sort((a, b) => a[0] - b[0]);
        const [minEdgeCost, node, totalCost] = pq.shift()!;

        if (visited.has(node)) continue;
        visited.add(node);

        // If we reached the destination node, update maxMinEdgeCost
        if (node === n - 1) {
            maxMinEdgeCost[n - 1] = Math.max(maxMinEdgeCost[n - 1], minEdgeCost);
            continue;
        }

        // Explore neighbors
        if (graph.has(node)) {
            for (const [neighbor, cost] of graph.get(node)!.entries()) {
                // Check if the neighbor is online
                if (!online[neighbor]) continue;

                // Check if the total cost is within k
                if (totalCost + cost > k) continue;

                // Update the priority queue with the new minEdgeCost and totalCost
                const newMinEdgeCost = Math.min(minEdgeCost, cost);
                pq.push([newMinEdgeCost, neighbor, totalCost + cost]);
            }
        }
    }

    return maxMinEdgeCost[n - 1];
}

