        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let cost = edge[2];
        if !graph.contains_key(u) {
            graph.insert(u, std::collections::HashMap::new());
        }
        graph.get_mut(u).unwrap().insert(v, cost);
    }

    // Use a priority queue for Dijkstra's algorithm, sorted by minimum edge cost
