                if total_cost + cost > k {
                    continue;
                }

                // Update the priority queue with the new minEdgeCost and totalCost
                let new_min_edge_cost = std::cmp::min(min_edge_cost, cost);
                pq.push((new_min_edge_cost, neighbor, total_cost + cost));
            }
        }
